// Process outreach performance data to build context for content generation
// This tells the Content Agent what reel formats are working best
const input = $('Query Outreach Performance').first().json;

// Handle missing data gracefully - query may return empty array or error
let topFormats = [];
let contextSummary = 'No outreach performance data available yet. Using default content strategy.';

try {
  const rows = Array.isArray(input) ? input : (input.data || input.body || []);
  if (Array.isArray(rows) && rows.length > 0) {
    topFormats = rows.map(r => ({
      channel: r.channel || 'unknown',
      angle: r.angle || 'unknown',
      tone: r.tone || 'unknown',
      positive_rate_pct: r.positive_rate_pct || 0,
      total_sent: r.total_sent || 0
    }));
    contextSummary = 'Top performing formats:\n' + topFormats.map((f, i) =>
      `${i + 1}. ${f.channel} / ${f.angle} / ${f.tone} - ${f.positive_rate_pct}% positive (${f.total_sent} posts)`
    ).join('\n');
  }
} catch (e) {
  // Gracefully handle any parsing errors
  contextSummary = 'Outreach performance query failed: ' + (e.message || 'unknown error') + '. Using default content strategy.';
}

return [{
  json: {
    topFormats,
    contextSummary,
    hasPerformanceData: topFormats.length > 0
  }
}];

// Try today's report first, fall back to checking if we got content
const input = $('Read Content Report').first().json;
const rawContent = input.content || '';

// Get outreach performance context (may not exist yet)
let outreachContext = 'No outreach performance data available yet.';
try {
  const outreachData = $('Prepare Outreach Context').first().json;
  outreachContext = outreachData.contextSummary || outreachContext;
} catch (e) {
  // Outreach context not available, continue with default
}

if (!rawContent) {
  return [{ json: { error: 'No content report found for today', reels: [], hasReels: false, outreachContext } }];
}

// Decode base64 if needed (GitHub API returns base64)
let content = rawContent;
try {
  if (rawContent.match(/^[A-Za-z0-9+/=\s]+$/) && rawContent.length > 50) {
    content = Buffer.from(rawContent, 'base64').toString('utf-8');
  }
} catch (e) {
  // Already plaintext
}

// Parse reel scripts from content report
// Content Agent uses ---PIECE--- separators with type indicators
const pieces = content.split('---PIECE---').map(p => p.trim()).filter(Boolean);
const reels = [];

for (const piece of pieces) {
  const typeMatch = piece.match(/type:\s*reel/i);
  if (!typeMatch) continue;

  // Extract hook, body, CTA from reel script
  const hookMatch = piece.match(/hook:\s*(.+?)(?:\n|$)/i) || piece.match(/\*\*hook\*\*:\s*(.+?)(?:\n|$)/i);
  const ctaMatch = piece.match(/cta:\s*(.+?)(?:\n|$)/i) || piece.match(/\*\*cta\*\*:\s*(.+?)(?:\n|$)/i);

  // Get the body: everything between hook/body markers and CTA
  let body = '';
  const bodyMatch = piece.match(/body:\s*([\s\S]*?)(?=cta:|\*\*cta\*\*:|$)/i);
  if (bodyMatch) {
    body = bodyMatch[1].trim();
  }

  // If structured parsing fails, use the whole piece as script text
  const hook = hookMatch ? hookMatch[1].trim() : '';
  const cta = ctaMatch ? ctaMatch[1].trim() : '';
  const fullScript = hook ? `${hook}\n\n${body}\n\n${cta}` : piece.replace(/type:\s*reel\s*/i, '').trim();

  // Extract title if present
  const titleMatch = piece.match(/title:\s*(.+?)(?:\n|$)/i);
  const title = titleMatch ? titleMatch[1].trim() : `BayFlow Reel ${reels.length + 1}`;

  // Extract tone and angle if present in the piece
  const toneMatch = piece.match(/tone:\s*(.+?)(?:\n|$)/i);
  const angleMatch = piece.match(/angle:\s*(.+?)(?:\n|$)/i);

  reels.push({
    title,
    hook,
    body,
    cta,
    fullScript,
    tone: toneMatch ? toneMatch[1].trim() : 'casual',
    angle: angleMatch ? angleMatch[1].trim() : 'tip',
    index: reels.length
  });
}

// If no structured reels found, try to find reel-like sections by headers
if (reels.length === 0) {
  const reelSections = content.match(/##\s*reel[\s\S]*?(?=##\s|$)/gi) || [];
  for (const section of reelSections) {
    const titleMatch = section.match(/##\s*reel\s*\d*:?\s*(.+?)(?:\n|$)/i);
    reels.push({
      title: titleMatch ? titleMatch[1].trim() : `BayFlow Reel ${reels.length + 1}`,
      hook: '',
      body: '',
      cta: '',
      fullScript: section.replace(/##\s*reel\s*\d*:?\s*.+?\n/i, '').trim(),
      tone: 'casual',
      angle: 'tip',
      index: reels.length
    });
  }
}

return [{
  json: {
    reels,
    hasReels: reels.length > 0,
    reelCount: reels.length,
    reportDate: $now.toFormat('yyyy-MM-dd'),
    outreachContext
  }
}];

// Split reels array into individual items for processing
const data = $('Parse Reel Scripts').first().json;
const reels = data.reels || [];
const reportDate = data.reportDate;
const outreachContext = data.outreachContext || '';

return reels.map(reel => ({
  json: {
    ...reel,
    reportDate,
    outreachContext
  }
}));

// Check if Revid.ai generation was submitted successfully
const input = $input.first().json;
const reelData = $('Split Into Individual Reels').item;
const hasError = input.error || input.statusCode >= 400 || !input.id;

if (hasError) {
  // Revid.ai not configured or failed - continue with text-only posting
  return [{
    json: {
      ...reelData.json,
      videoGenerated: false,
      videoId: null,
      videoUrl: null,
      videoStatus: 'skipped',
      reason: input.error || input.message || 'Revid.ai not configured or returned error'
    }
  }];
}

// Revid.ai is async - store the generation ID for polling
return [{
  json: {
    ...reelData.json,
    videoGenerated: true,
    videoId: input.id || input.generation_id || null,
    videoUrl: input.video_url || null,
    videoStatus: input.status || 'processing',
    reason: null
  }
}];

// Merge poll results with reel data
const pollResult = $input.first().json;
const reelData = $('Check Revid Response').item.json;

const videoUrl = pollResult.video_url || pollResult.download_url || null;
const isComplete = pollResult.status === 'completed' || pollResult.status === 'done' || !!videoUrl;

return [{
  json: {
    ...reelData,
    videoUrl: videoUrl,
    videoStatus: isComplete ? 'completed' : (pollResult.status || 'unknown'),
    videoGenerated: isComplete && !!videoUrl
  }
}];

// Prepare the social media post payload
// Works whether video was generated or not (text-only fallback)
const reel = $input.first().json;

const hasVideo = reel.videoGenerated && reel.videoUrl;
const caption = reel.hook 
  ? `${reel.hook}\n\n${reel.body ? reel.body.substring(0, 200) : ''}\n\n${reel.cta || 'Try BayFlow free today!'}\n\n#autorepair #shopmanagement #bayflow #autoshop #mechaniclife`
  : `${reel.fullScript.substring(0, 300)}\n\n#autorepair #shopmanagement #bayflow #autoshop #mechaniclife`;

return [{
  json: {
    ...reel,
    caption,
    hasVideo,
    mediaUrl: hasVideo ? reel.videoUrl : null,
    postType: hasVideo ? 'video' : 'text'
  }
}];

