// Collect all posting results and build a summary per reel
const reel = $('Prepare Social Post').item.json;
const mixpostResult = $('Post via Mixpost').item.json;
const tiktokResult = $('Post to TikTok (Direct)').item.json;

const mixpostOk = !(mixpostResult.error || mixpostResult.statusCode >= 400);
const tiktokOk = !(tiktokResult.error || tiktokResult.statusCode >= 400);

const platforms = [];
if (mixpostOk) platforms.push('Mixpost (draft)');
if (tiktokOk) platforms.push('TikTok');

return [{
  json: {
    title: reel.title,
    index: reel.index,
    caption: reel.caption,
    postType: reel.postType,
    hasVideo: reel.hasVideo,
    videoUrl: reel.videoUrl || null,
    videoStatus: reel.videoStatus || 'skipped',
    tone: reel.tone || 'casual',
    angle: reel.angle || 'tip',
    mixpostPosted: mixpostOk,
    tiktokPosted: tiktokOk,
    platformsPosted: platforms,
    mixpostError: mixpostOk ? null : (mixpostResult.error || mixpostResult.message || 'Not configured'),
    tiktokError: tiktokOk ? null : (tiktokResult.error || tiktokResult.message || 'Not configured'),
    reportDate: reel.reportDate
  }
}];

// Aggregate all reel results into a single report
const items = $input.all();
const reportDate = items[0]?.json?.reportDate || new Date().toISOString().split('T')[0];

let report = `# Social Media Publisher Report - ${reportDate}\n\n`;
report += `## Summary\n`;
report += `- Reels processed: ${items.length}\n`;
report += `- Videos generated: ${items.filter(i => i.json.hasVideo).length}\n`;
report += `- Successfully posted: ${items.filter(i => i.json.platformsPosted.length > 0).length}\n\n`;

for (const item of items) {
  const r = item.json;
  report += `## Reel ${r.index + 1}: ${r.title}\n`;
  report += `- Type: ${r.postType}\n`;
  report += `- Video status: ${r.videoStatus}\n`;
  if (r.videoUrl) report += `- Video URL: ${r.videoUrl}\n`;
  report += `- Platforms posted: ${r.platformsPosted.length > 0 ? r.platformsPosted.join(', ') : 'None (services not configured)'}\n`;
  if (r.mixpostError) report += `- Mixpost: ${r.mixpostError}\n`;
  if (r.tiktokError) report += `- TikTok: ${r.tiktokError}\n`;
  report += `\n`;
}

report += `## Next Steps\n`;
report += `- Configure REVID_API_KEY for video generation\n`;
report += `- Configure MIXPOST_URL and MIXPOST_API_KEY for social scheduling\n`;
report += `- Configure TIKTOK_ACCESS_TOKEN for direct TikTok posting\n`;

// Build Supabase row for knowledge graph
const performanceRows = items.map(item => ({
  business_id: 'bayflow',
  content_type: 'reel',
  title: item.json.title,
  platform: item.json.platformsPosted.join(',') || 'none',
  published_at: reportDate,
  video_url: item.json.videoUrl || null,
  status: item.json.platformsPosted.length > 0 ? 'published' : 'draft'
}));

// Build outreach_intelligence rows for each platform per reel
const now = new Date();
const outreachRows = [];
for (const item of items) {
  const r = item.json;
  const caption = r.caption || '';
  const platforms = r.platformsPosted || [];
  const hasVideo = r.hasVideo || false;
  const platformList = platforms.length > 0 ? platforms.map(p => p.replace(' (draft)', '').toLowerCase()) : ['tiktok', 'instagram'];

  for (const platform of platformList) {
    outreachRows.push({
      business_id: 'bayflow',
      channel: platform,
      outreach_type: 'social_post',
      audience_type: 'auto_repair',
      tone: r.tone || 'casual',
      angle: r.angle || 'tip',
      intent: 'build_awareness',
      content_preview: caption.substring(0, 200),
      personalization_depth: 0,
      day_of_week: now.getDay(),
      hour_of_day: now.getHours(),
      outcome: 'pending',
      lead_email: null,
      notes: 'Posted to ' + platforms.join(', ') + '. Video: ' + (hasVideo ? 'yes' : 'text only')
    });
  }
}

return [{
  json: {
    report,
    reportDate,
    performanceRows,
    outreachRows,
    totalReels: items.length,
    videosGenerated: items.filter(i => i.json.hasVideo).length,
    postsPublished: items.filter(i => i.json.platformsPosted.length > 0).length
  }
}];

// No reels found - log a skip report
const now = new Date().toISOString().split('T')[0];
return [{
  json: {
    report: `# Social Media Publisher Report - ${now}\n\nNo reel scripts found in today's content report.\nCheck that Content Agent has run and produced reel scripts in the content report.\n`,
    reportDate: now
  }
}];
